// Package v1 contains the generated gRPC stubs for the Zynax v1 API.
// These files are generated by buf from the .proto sources in protos/zynax/v1/.
//
// To regenerate all stubs (requires buf and Docker via make):
//
//	make generate-protos
//
// To regenerate using a locally installed buf (no Docker):
//
//go:generate sh -c "cd $(git rev-parse --show-toplevel)/protos && buf generate --template buf.gen.yaml"
package zynaxv1
